pragma solidity ^0.8.20;

contract PostingBoard {
    struct Post {
        address author;
        string content;
        uint256 totalPower;
    }

    mapping(uint256 => Post) private posts;
    mapping(address => uint256) private authorBalances;
    uint256 public postCount;

    event PostCreated(uint256 postId, address author, string content);
    event PostBoosted(uint256 postId, uint256 amount);
    event Withdrawn(address author, uint256 amount);

    function createPost(string calldata content) external returns (uint256) {
        require(bytes(content).length > 0, "Content cannot be empty");
        postCount++;
        posts[postCount] = Post({
            author: msg.sender,
            content: content,
            totalPower: 0
        });
        emit PostCreated(postCount, msg.sender, content);
        return postCount;
    }

    function boostPost(uint256 postId) external payable {
        require(postId <= postCount, "Post does not exist");
        require(msg.value > 0, "Boost value must be greater than 0");
        Post storage post = posts[postId];
        require(post.author != address(0), "Invalid post ID");

        post.totalPower += msg.value;
        authorBalances[post.author] += msg.value;

        emit PostBoosted(postId, msg.value);
    }

    function authorBalances(address author) external view returns (uint256) {
        return authorBalances[author];
    }

    function withdraw() external {
        uint256 balance = authorBalances[msg.sender];
        require(balance > 0, "No balance to withdraw");
        authorBalances[msg.sender] = 0;
        (bool sent, ) = msg.sender.call{value: balance}("");
        require(sent, "Failed to send Ether");
        emit Withdrawn(msg.sender, balance);
    }

    function getPost(uint256 postId) external view returns (address, string memory, uint256) {
        require(postId <= postCount, "Post does not exist");
        Post memory post = posts[postId];
        return (post.author, post.content, post.totalPower);
    }
}
